1	/* ═════════════════════════════════════════════════════════════════════════
2	 * Theseus Codex — unified globals source of truth
3	 *
4	 * This file now owns both the founder portal and the migrated public pages.
5	 * Public-site classes are scoped with `public-*`; generic public globals from
6	 * theseus-public are intentionally not imported.
7	 *
8	 * "Amber Oracle" aesthetic
9	 *
10	 * Terminal-inspired amber CRT on charcoal, classical Roman typography,
11	 * subtle scan-line phosphor glow. Text-first (EB Garamond for body,
12	 * Cinzel for display), monospace (IBM Plex Mono) for numeric / terminal
13	 * accents, with box-drawing characters as UI chrome.
14	 *
15	 * Palette shift from prior version: gold-amber is now the dominant accent
16	 * with a stronger CRT-orange fallback (`--amber`), and the whole UI sits
17	 * over a near-black charcoal rather than warm stone, so the phosphor glow
18	 * actually looks like phosphor.
19	 *
20	 * Scan-line overlay + amber vignette are provided by <CRTOverlay /> in
21	 * the root layout — don't add them here so they can be disabled per-user
22	 * via prefers-reduced-motion or a future user preference.
23	 * ═════════════════════════════════════════════════════════════════════════ */
24	
25	@import url('https://fonts.googleapis.com/css2?family=EB+Garamond:ital,wght@0,400;0,500;0,600;1,400;1,500&family=Cinzel:wght@400;500;600;700&family=Cinzel+Decorative:wght@400;700&family=Inter:wght@300;400;500&family=IBM+Plex+Mono:ital,wght@0,300;0,400;0,500;0,600;1,400&display=swap');
26	@import "tailwindcss";
27	
28	/* ── Theseus Design Tokens — Amber Oracle ────────────────────────────────── */
29	
30	:root {
31	  color-scheme: dark;
32	  --ink:          var(--stone);  /* codex-origin: public-site background alias */
33	  --stone:        #08070a;   /* codex-origin: void background */
34	  --stone-light:  #120f0b;   /* codex-origin: card surfaces */
35	  --stone-mid:    #1b1612;   /* codex-origin: raised/input surfaces */
36	  --amber:        #e9a338;   /* codex-origin: links, active nav, highlights */
37	  --amber-dim:    #a8762a;   /* codex-origin: metadata and quiet accents */
38	  --amber-deep:   #5e4617;   /* codex-origin: disabled/subtle borders */
39	  --amber-glow:   rgba(233, 163, 56, 0.35);  /* codex-origin: drop-shadows */
40	  --parchment:    #efe2c7;   /* codex-origin: primary readable foreground */
41	  --parchment-dim:#9c8f72;   /* codex-origin: secondary readable foreground */
42	  --gold:         var(--amber);      /* codex-origin: legacy alias */
43	  --gold-dim:     var(--amber-dim);  /* codex-origin: legacy alias */
44	  --ember:        #c94a1f;   /* codex-origin: error/action heat */
45	  --border:       #3a2d12;   /* codex-origin: kept over public --border conflict */
46	  --success:      #7ea83a;   /* codex-origin: success state */
47	  --info:         #3a7aa8;   /* codex-origin: informational state */
48	  --glow-sm: 0 0 6px var(--amber-glow);  /* codex-origin: small phosphor glow */
49	  --glow-md: 0 0 14px var(--amber-glow), 0 0 2px var(--amber);  /* codex-origin: medium phosphor glow */
50	  --glow-lg: 0 0 28px var(--amber-glow), 0 0 4px var(--amber);  /* codex-origin: large phosphor glow */
51	}
52	
53	[data-theme="light"] {
54	  color-scheme: light;
55	  --ink:          var(--stone);  /* codex-origin light: public-site background alias */
56	  --stone:        #f2e8d9;   /* codex-origin light: parchment background */
57	  --stone-light:  #ede0cc;   /* codex-origin light: card surfaces */
58	  --stone-mid:    #e4d4ba;   /* codex-origin light: raised/input surfaces */
59	  --amber:        #7a5218;   /* codex-origin light: links and highlights */
60	  --amber-dim:    #9a6c28;   /* codex-origin light: metadata and quiet accents */
61	  --amber-deep:   #c1a670;   /* codex-origin light: disabled/subtle borders */
62	  --amber-glow:   rgba(122, 82, 24, 0.18);  /* codex-origin light: drop-shadows */
63	  --parchment:    #2a2318;   /* codex-origin light: primary foreground */
64	  --parchment-dim:#5a4e3a;   /* codex-origin light: secondary foreground */
65	  --gold:         var(--amber);      /* codex-origin light: legacy alias */
66	  --gold-dim:     var(--amber-dim);  /* codex-origin light: legacy alias */
67	  --ember:        #8b3a2a;   /* codex-origin light: error/action heat */
68	  --border:       #cbbfa8;   /* codex-origin light: kept over public --border conflict */
69	  --success:      #3a6a2a;   /* codex-origin light: success state */
70	  --info:         #2a4a6a;   /* codex-origin light: informational state */
71	  --glow-sm: 0 0 6px var(--amber-glow);  /* codex-origin light: small phosphor glow */
72	  --glow-md: 0 0 14px var(--amber-glow);  /* codex-origin light: medium glow */
73	  --glow-lg: 0 0 22px var(--amber-glow);  /* codex-origin light: large glow */
74	}
75	
76	html { transition: background 0.25s, color 0.25s; }
77	
78	@theme inline {
79	  --color-background: var(--stone);      /* codex-origin: Tailwind background mapping */
80	  --color-foreground: var(--parchment);  /* codex-origin: Tailwind foreground mapping */
81	}
82	
83	* { box-sizing: border-box; }
84	
85	html, html[data-theme] {
86	  background-color: var(--stone);
87	  color: var(--parchment);
88	}
89	
90	body {
91	  background-color: var(--stone);
92	  color: var(--parchment);
93	  font-family: 'EB Garamond', Georgia, serif;
94	  font-size: 17px;
95	  line-height: 1.7;
96	  min-height: 100vh;
97	  /* Faint amber tint on body text itself, so the whole UI feels bathed in
98	     phosphor. Not so strong that body text becomes hard to read. */
99	  text-shadow: 0 0 1px rgba(233, 163, 56, 0.05);
100	}
101	
102	.skip-link {
103	  background: var(--amber);
104	  border: 1px solid var(--parchment);
105	  box-shadow: 0 0 0 2px var(--stone), var(--glow-sm);
106	  color: var(--stone);
107	  font-family: "IBM Plex Mono", monospace;
108	  font-size: 0.75rem;
109	  font-weight: 700;
110	  left: 1rem;
111	  letter-spacing: 0.12em;
112	  padding: 0.55rem 0.75rem;
113	  position: fixed;
114	  text-decoration: none;
115	  text-transform: uppercase;
116	  top: 0.75rem;
117	  transform: translateY(-160%);
118	  transition: transform 160ms ease;
119	  z-index: 10000;
120	}
121	
122	.skip-link:focus,
123	.skip-link:focus-visible {
124	  outline: 2px solid var(--parchment);
125	  outline-offset: 2px;
126	  transform: translateY(0);
127	}
128	
129	.skip-link:focus:not(:focus-visible) {
130	  transform: translateY(-160%);
131	}
132	
133	#main-content:focus,
134	[data-skip-focus-target]:focus {
135	  outline: none;
136	}
137	
138	@media (prefers-reduced-motion: reduce) {
139	  .skip-link {
140	    transition: none;
141	  }
142	}
143	
144	h1, h2, h3, h4 {
145	  font-family: 'Cinzel', 'Palatino Linotype', serif;
146	  font-weight: 500;
147	  letter-spacing: 0.05em;
148	}
149	
150	/* ── Mono utility class for terminal-style text (timestamps, IDs, numbers) ── */
151	.mono, code, pre, kbd {
152	  font-family: 'IBM Plex Mono', 'JetBrains Mono', Menlo, monospace;
153	  font-feature-settings: "tnum" 1, "ss01" 1;  /* tabular figures */
154	}
155	
156	/* ── Scrollbar — CRT-thin, amber on hover ───────────────────────────────── */
157	::-webkit-scrollbar { width: 6px; }
158	::-webkit-scrollbar-track { background: var(--stone); }
159	::-webkit-scrollbar-thumb { background: var(--border); border-radius: 3px; }
160	::-webkit-scrollbar-thumb:hover { background: var(--amber-dim); }
161	::selection { background: var(--amber-dim); color: var(--stone); text-shadow: none; }
162	
163	/* ── Form elements ───────────────────────────────────────────────────────── */
164	input, textarea, select {
165	  background: var(--stone-mid);
166	  border: 1px solid var(--border);
167	  color: var(--parchment);
168	  font-family: 'EB Garamond', Georgia, serif;
169	  font-size: 1rem;
170	  padding: 0.6rem 0.9rem;
171	  border-radius: 2px;
172	  outline: none;
173	  transition: border-color 0.2s, box-shadow 0.2s;
174	  width: 100%;
175	}
176	
177	input:focus, textarea:focus, select:focus {
178	  border-color: var(--amber);
179	  box-shadow: var(--glow-sm);
180	}
181	
182	input::placeholder, textarea::placeholder {
183	  color: var(--parchment-dim);
184	  opacity: 0.5;
185	}
186	
187	/* ── Buttons — amber with phosphor glow on hover ─────────────────────────── */
188	.btn {
189	  font-family: 'Cinzel', serif;
190	  font-size: 0.75rem;
191	  letter-spacing: 0.12em;
192	  text-transform: uppercase;
193	  padding: 0.6rem 1.4rem;
194	  border: 1px solid var(--amber-dim);
195	  background: transparent;
196	  color: var(--amber);
197	  cursor: pointer;
198	  transition: all 0.2s;
199	  border-radius: 1px;
200	  text-shadow: 0 0 1px var(--amber-glow);
201	}
202	
203	.btn:hover {
204	  background: var(--amber-dim);
205	  color: var(--stone);
206	  box-shadow: var(--glow-md);
207	  text-shadow: none;
208	}
209	
210	.btn:focus-visible {
211	  outline: none;
212	  box-shadow: var(--glow-lg);
213	}
214	
215	.btn-solid {
216	  background: var(--amber-dim);
217	  color: var(--stone);
218	  border-color: var(--amber-dim);
219	  text-shadow: none;
220	}
221	
222	.btn-solid:hover {
223	  background: var(--amber);
224	  border-color: var(--amber);
225	  box-shadow: var(--glow-lg);
226	}
227	
228	/* ── Cards ───────────────────────────────────────────────────────────────── */
229	.portal-card {
230	  background: var(--stone-light);
231	  border: 1px solid var(--border);
232	  border-radius: 2px;
233	  padding: 1.5rem;
234	  transition: border-color 0.2s, box-shadow 0.2s, transform 0.15s;
235	  position: relative;
236	}
237	
238	.portal-card:hover {
239	  border-color: var(--amber-dim);
240	  box-shadow: var(--glow-sm);
241	}
242	
243	/* ── Migrated public publication pages ─────────────────────────────────────
244	 * These are prefixed ports of theseus-public's `.container`, `.card`,
245	 * `.muted`, and `.hr` utilities. They use Codex-origin tokens rather than
246	 * reintroducing the old public global variables.
247	 */
248	.public-container {
249	  max-width: 860px;
250	  margin: 0 auto;
251	  padding: 2.25rem 1.25rem 4rem;
252	  position: relative;
253	  z-index: 1;
254	}
255	
256	.public-container a {
257	  color: var(--amber);
258	}
259	
260	.public-title {
261	  font-family: 'EB Garamond', 'Iowan Old Style', Georgia, serif;
262	  font-size: clamp(1.85rem, 4.4vw, 2.6rem);
263	  font-weight: 600;
264	  letter-spacing: -0.005em;
265	  line-height: 1.18;
266	  margin: 0;
267	  color: var(--amber);
268	  text-shadow: var(--glow-sm);
269	}
270	
271	.public-article-body {
272	  text-align: justify;
273	  text-justify: inter-word;
274	  hyphens: auto;
275	  -webkit-hyphens: auto;
276	  hyphenate-limit-chars: 6 3 3;
277	  hyphenate-limit-lines: 2;
278	  text-wrap: pretty;
279	  max-width: 70ch;
280	}
281	
282	.public-article-body :where(ul, ol, li, blockquote, pre, code, table) {
283	  text-align: start;
284	  hyphens: manual;
285	  -webkit-hyphens: manual;
286	}
287	
288	.public-lede {
289	  max-width: 75ch;
290	  margin-top: 0.85rem;
291	  font-size: 1rem;
292	}
293	
294	.public-muted {
295	  color: var(--parchment-dim);
296	}
297	
298	.public-kicker {
299	  margin-top: 0;
300	  font-size: 0.85rem;
301	}
302	
303	.public-card {
304	  border: 1px solid var(--border);
305	  background: var(--stone-light);
306	  border-radius: 2px;
307	  padding: 1rem 1.1rem;
308	  margin-top: 0.75rem;
309	}
310	
311	.public-card h2,
312	.public-section h2 {
313	  font-size: 1rem;
314	  margin: 0;
315	  color: var(--amber);
316	}
317	
318	.public-card p {
319	  margin: 0.65rem 0 0;
320	}
321	
322	.public-section {
323	  margin-top: 1.25rem;
324	}
325	
326	.public-section-heading {
327	  align-items: baseline;
328	  display: flex;
329	  flex-wrap: wrap;
330	  gap: 0.6rem 1rem;
331	  justify-content: space-between;
332	}
333	
334	.public-section-link {
335	  border: 1px solid var(--amber-deep);
336	  color: var(--amber);
337	  font-size: 0.62rem;
338	  letter-spacing: 0.16em;
339	  padding: 0.34rem 0.5rem;
340	  text-decoration: none;
341	  text-transform: uppercase;
342	}
343	
344	.public-section-link:focus-visible {
345	  outline: 2px solid var(--amber);
346	  outline-offset: 3px;
347	}
348	
349	.public-section p {
350	  max-width: 75ch;
351	  margin: 0.5rem 0 0;
352	}
353	
354	.public-section ul,
355	.public-section ol {
356	  margin: 0.6rem 0 0;
357	  padding-left: 1.2rem;
358	}
359	
360	.public-section li {
361	  margin: 0.35rem 0;
362	}
363	
364	.public-method-grid {
365	  display: grid;
366	  gap: 0.85rem;
367	  grid-template-columns: repeat(auto-fit, minmax(min(100%, 240px), 1fr));
368	  margin-top: 0.85rem;
369	}
370	
371	.public-method-split {
372	  display: grid;
373	  gap: 0.85rem;
374	  grid-template-columns: repeat(2, minmax(0, 1fr));
375	  margin-top: 0.85rem;
376	}
377	
378	.public-method-card {
379	  display: grid;
380	  gap: 0.65rem;
381	  margin-top: 0;
382	  min-width: 0;
383	}
384	
385	.public-method-card h3 {
386	  color: var(--amber);
387	  font-size: 0.95rem;
388	  line-height: 1.25;
389	  margin: 0;
390	}
391	
392	.public-method-card p {
393	  margin: 0;
394	}
395	
396	.public-method-meta {
397	  align-items: center;
398	  color: var(--amber-dim);
399	  display: flex;
400	  flex-wrap: wrap;
401	  font-size: 0.58rem;
402	  gap: 0.4rem 0.65rem;
403	  justify-content: space-between;
404	  letter-spacing: 0.16em;
405	  text-transform: uppercase;
406	}
407	
408	.public-method-summary {
409	  color: var(--parchment);
410	  font-size: 0.95rem;
411	  line-height: 1.5;
412	}
413	
414	.public-method-note {
415	  background: rgba(232, 225, 211, 0.035);
416	  color: var(--parchment-dim);
417	}
418	
419	.public-method-note.public-card {
420	  margin-top: 0.75rem;
421	}
422	
423	.public-method-note p {
424	  margin: 0;
425	}
426	
427	.public-method-narrative {
428	  color: var(--parchment);
429	}
430	
431	.public-method-list-group {
432	  border-top: 1px solid rgba(232, 225, 211, 0.1);
433	  padding-top: 0.6rem;
434	}
435	
436	.public-method-list-group h4 {
437	  color: var(--parchment-dim);
438	  font-size: 0.58rem;
439	  letter-spacing: 0.16em;
440	  margin: 0 0 0.35rem;
441	  text-transform: uppercase;
442	}
443	
444	.public-method-list {
445	  display: grid;
446	  gap: 0.28rem;
447	  list-style: none;
448	  margin: 0;
449	  padding: 0;
450	}
451	
452	.public-method-list li {
453	  color: var(--parchment-dim);
454	  font-size: 0.9rem;
455	  line-height: 1.45;
456	  margin: 0;
457	  padding-left: 0.85rem;
458	  position: relative;
459	}
460	
461	.public-method-list li::before {
462	  background: var(--amber-dim);
463	  content: "";
464	  height: 0.28rem;
465	  left: 0;
466	  position: absolute;
467	  top: 0.58rem;
468	  width: 0.28rem;
469	}
470	
471	.public-hr {
472	  height: 1px;
473	  background: var(--border);
474	  border: 0;
475	  margin: 1.25rem 0;
476	}
477	
478	.public-inline-stat {
479	  margin-left: 0.65rem;
480	}
481	
482	.public-citation {
483	  margin-top: 0.85rem;
484	}
485	
486	.public-citation-head {
487	  display: flex;
488	  justify-content: space-between;
489	  gap: 0.75rem;
490	  align-items: center;
491	}
492	
493	.public-citation-head .mono {
494	  font-size: 0.85rem;
495	  text-transform: uppercase;
496	  letter-spacing: 0.08em;
497	}
498	
499	.public-pre {
500	  margin-top: 0.5rem;
501	  padding: 0.75rem;
502	  border: 1px solid var(--border);
503	  border-radius: 2px;
504	  overflow-x: auto;
505	  font-size: 0.85rem;
506	  background: var(--stone-mid);
507	  color: var(--parchment);
508	  white-space: pre;
509	}
510	
511	.public-section .public-response-list {
512	  list-style: none;
513	  padding: 0;
514	  margin: 0;
515	  display: flex;
516	  flex-direction: column;
517	  gap: 0.75rem;
518	}
519	
520	.public-section .public-response-list .mono {
521	  font-size: 0.8rem;
522	}
523	
524	.public-section .firm-source-list {
525	  list-style: decimal;
526	  margin: 0.55rem 0 0;
527	  padding-left: 1.15rem;
528	}
529	
530	.firm-source-row {
531	  border-bottom: 1px dashed var(--border);
532	  box-shadow: none;
533	  color: var(--parchment);
534	  line-height: 1.5;
535	  margin: 0;
536	  padding: 0.45rem 0;
537	  overflow-wrap: anywhere;
538	}
539	
540	.firm-source-row:last-child {
541	  border-bottom: 0;
542	}
543	
544	.firm-source-row a,
545	.firm-source-row span {
546	  display: block;
547	}
548	
549	.firm-source-row a {
550	  color: var(--amber);
551	  text-decoration-color: rgba(210, 163, 73, 0.45);
552	  text-underline-offset: 0.18em;
553	}
554	
555	.firm-source-row .mono {
556	  color: var(--parchment-dim);
557	  display: block;
558	  font-size: 0.68rem;
559	  letter-spacing: 0.08em;
560	  margin-top: 0.18rem;
561	}
562	
563	.public-footer-link {
564	  margin-top: 1.75rem;
565	}
566	
567	.public-form-card {
568	  margin-top: 1.25rem;
569	}
570	
571	.public-label {
572	  color: var(--parchment-dim);
573	  font-size: 0.9rem;
574	  display: block;
575	  margin-top: 0.75rem;
576	}
577	
578	.public-label input,
579	.public-label select,
580	.public-label textarea {
581	  display: block;
582	  width: 100%;
583	  margin-top: 0.35rem;
584	}
585	
586	.public-field-error {
587	  color: var(--ember);
588	  font-family: 'IBM Plex Mono', monospace;
589	  font-size: 0.72rem;
590	  line-height: 1.45;
591	  margin: -0.35rem 0 0;
592	}
593	
594	.public-form-status {
595	  color: var(--amber);
596	  font-family: 'IBM Plex Mono', monospace;
597	  font-size: 0.76rem;
598	  min-height: 1.4rem;
599	}
600	
601	.btn:disabled,
602	.btn:disabled:hover {
603	  background: transparent;
604	  border-color: var(--amber-deep);
605	  box-shadow: none;
606	  color: var(--parchment-dim);
607	  cursor: wait;
608	}
609	
610	.public-checkbox {
611	  color: var(--parchment-dim);
612	  display: flex;
613	  gap: 0.5rem;
614	  align-items: center;
615	  margin-top: 0.75rem;
616	}
617	
618	.public-checkbox input {
619	  width: auto;
620	}
621	
622	@media (max-width: 720px) {
623	  .public-container {
624	    padding: 1.75rem 1rem 3.5rem;
625	  }
626	
627	  .public-method-split {
628	    grid-template-columns: 1fr;
629	  }
630	
631	  .public-section-heading {
632	    align-items: flex-start;
633	    flex-direction: column;
634	  }
635	
636	  .public-inline-stat {
637	    display: block;
638	    margin-left: 0;
639	    margin-top: 0.35rem;
640	  }
641	
642	  .public-citation-head {
643	    align-items: flex-start;
644	    flex-direction: column;
645	  }
646	}
647	
648	/* ── Upload zone ─────────────────────────────────────────────────────────── */
649	.upload-zone {
650	  border: 2px dashed var(--border);
651	  border-radius: 2px;
652	  padding: 3rem 2rem;
653	  text-align: center;
654	  transition: all 0.2s;
655	  cursor: pointer;
656	}
657	
658	.upload-zone:hover, .upload-zone.dragover {
659	  border-color: var(--amber);
660	  background: var(--stone-light);
661	  box-shadow: var(--glow-md);
662	}
663	
664	/* ── Status badges ───────────────────────────────────────────────────────── */
